generated_oml:
// SensingComponents
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor on the permanent‑magnet synchronous motor (captures motor current for friction analysis)"
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance MotorPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor encoder (captures motor shaft position for joint angle reconstruction)"
    DTDFVocab:producedData MotorPositionDataTransmitted
]

instance GearWheelEncoder : DTDFVocab:SensingComponent [
    base:desc "Gear wheel encoder (captures gear‑stage position for joint kinematics)"
    DTDFVocab:producedData GearWheelPositionDataTransmitted
]

// DataTransmitted instances
instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorPositionEncoder
]

instance GearWheelPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearWheelEncoder
]

// Data instances
instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Motor current data stream received via MQTT from the current sensor"
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo MQTTDataTransportEnabler, SimulinkSimulationEnabler
]

instance MotorPositionData : DTDFVocab:Data [
    base:desc "Motor shaft angle data stream received via MQTT from the motor encoder"
    DTDFVocab:fromData MotorPositionDataTransmitted
    DTDFVocab:inputTo MQTTDataTransportEnabler, SimulinkSimulationEnabler
]

instance GearWheelPositionData : DTDFVocab:Data [
    base:desc "Gear wheel joint angle data stream received via MQTT from the gear wheel encoder"
    DTDFVocab:fromData GearWheelPositionDataTransmitted
    DTDFVocab:inputTo MQTTDataTransportEnabler, SimulinkSimulationEnabler
]

// Model instances
instance RobotStructureSysMLModel : DTDFVocab:Model [
    base:desc "Engineering model of the robot structure in SysML for reference in the digital twin"
    DTDFVocab:inputTo SysMLMBSEEnabler
]

instance CoulombViscousFrictionModel : DTDFVocab:Model [
    base:desc "Coulomb–Viscous friction model used in joint dynamics simulation"
    DTDFVocab:inputTo SimulinkSimulationEnabler
]

instance StribeckFrictionModel : DTDFVocab:Model [
    base:desc "Stribeck friction model used in joint dynamics simulation"
    DTDFVocab:inputTo SimulinkSimulationEnabler
]

instance DahlFrictionModel : DTDFVocab:Model [
    base:desc "Dahl friction model used in joint dynamics simulation"
    DTDFVocab:inputTo SimulinkSimulationEnabler
]

instance LuGreFrictionModel : DTDFVocab:Model [
    base:desc "LuGre friction model used in joint dynamics simulation"
    DTDFVocab:inputTo SimulinkSimulationEnabler
]

instance MotorGearboxSimModel : DTDFVocab:Model [
    base:desc "Simulink model of the motor, gearbox and friction dynamics"
    DTDFVocab:inputTo SimulinkSimulationEnabler
]

// Enabler instances
instance MQTTDataTransportEnabler : DTDFVocab:Enabler [
    base:desc "MQTT data transport enabling stream of sensor data from PT to DT"
    DTDFVocab:enables DataAggregationService
]

instance SimulinkSimulationEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink enabler for executable joint dynamics simulations"
    DTDFVocab:enables JointDynamicsSimulationService, RealTimeFrictionIdentificationService
]

instance SysMLMBSEEnabler : DTDFVocab:Enabler [
    base:desc "SysML MBSE enabler for engineering model creation and management"
]

instance AASStructuralBehavioralEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell enabler for structural and behavioral modeling"
    DTDFVocab:enables MultiPhysicsModelValidationService
]

instance WebDashboardEnabler : DTDFVocab:Enabler [
    base:desc "Web dashboard enabler for visualization of simulation results and insights"
    DTDFVocab:enables DashboardVisualizationService
]

// Service instances
instance DataAggregationService : DTDFVocab:Service [
    base:desc "Real‑time aggregation of motor current and position data streams for analysis"
    DTDFVocab:provides AssetHealthMetricInsight
]

instance JointDynamicsSimulationService : DTDFVocab:Service [
    base:desc "Simulation of joint dynamics using motor/gearbox and friction models"
]

instance RealTimeFrictionIdentificationService : DTDFVocab:Service [
    base:desc "Real‑time friction loss identification from simulations and sensor data"
    DTDFVocab:provides FrictionLossesInsight, DriftPredictionInsight, FrictionModelUpdateAction
]

instance MultiPhysicsModelValidationService : DTDFVocab:Service [
    base:desc "Multi‑physics‑aware model validation comparing measured and simulated data"
    DTDFVocab:provides MultiPhysicsValidationInsight
]

instance DashboardVisualizationService : DTDFVocab:Service [
    base:desc "Visualized results via dashboard for controller tuning and monitoring"
    DTDFVocab:provides DashboardVisualizationAction
]

instance DataAnalysisService : DTDFVocab:Service [
    base:desc "Analysis of aggregated data to extract asset health metrics"
    DTDFVocab:provides AssetHealthMetricInsight
]

// Insight instances
instance FrictionLossesInsight : DTDFVocab:Insight [
    base:desc "Insight on friction losses identified in the joint dynamics"
]

instance DriftPredictionInsight : DTDFVocab:Insight [
    base:desc "Insight predicting drift due to friction changes"
]

instance MultiPhysicsValidationInsight : DTDFVocab:Insight [
    base:desc "Insight on validation of multi‑physics models against experimental data"
]

// Action instances
instance FrictionModelUpdateAction : DTDFVocab:Action [
    base:desc "Automatic update of friction parameters in the controller model"
    DTDFVocab:IsAutomatic true
]

instance ControllerParameterTuningAction : DTDFVocab:Action [
    base:desc "Action to adjust controller parameters for improved motion accuracy"
    DTDFVocab:IsAutomatic true
]

instance MaintenanceScheduleAction : DTDFVocab:Action [
    base:desc "Action suggesting maintenance schedule based on friction analysis"
    DTDFVocab:IsAutomatic false
]

instance DashboardVisualizationAction : DTDFVocab:Action [
    base:desc "Action to render simulation results and insights on the web dashboard"
    DTDFVocab:IsAutomatic false
]

instance AssetHealthMetricInsight : DTDFVocab:Insight [
    base:desc "Insight on overall asset health metrics derived from sensor data"
]

// Environment and Component
instance DigitalTwinEnvironment : DTDFVocab:Environment [
    base:contains DigitalTwinContainer
]

instance DigitalTwinContainer : DTDFVocab:Component [
    base:desc "Monolithic digital twin of the first vertical axis of the MABI MAX 100 robot, integrating Sensing, Data, Models, Enablers, Services, Insights and Actions"
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous, real‑time; data are streamed at the robot’s sensor sampling rate (typically several hundred Hz) and processed instantly by the DT for live friction monitoring."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "PT + encoders + motor current sensor → MQTT broker → digital shadow processing component (Simulink, data calculation) → AAS as asset model → dashboard displaying real‑time friction analysis and model comparison."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Design (conceptual modeling in SysML), implementation (creation of simulation and calculation models in Simulink), deployment (dashboard and MQTT integration), and operation (continuous live monitoring and friction model updates)."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Combined white‑box and black‑box friction models allow continuous recalibration; model validity is assessed by comparing simulated torque/velocity traces to measured data (data trace provenance); limitations of each friction model type and sensor accuracy are acknowledged; uncertainty from load, temperature, and wear are considered through continuous identification."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "MQTT protocol used for transmitting sensor streams to the DT; Asset Administration Shell provides standardized interfaces for data access and command publication."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of SysML for engineering models, Simulink for executable models, Asset Administration Shells for semantic data representation, and MQTT for data transport aligns with industrial IoT and DT standards."
]
